        using var conn = Database.CreateConnection();
        return conn.Query<ColorSurcharge>(
            @"SELECT cs.*, m.Name AS MaterialName
              FROM ColorSurcharges cs LEFT JOIN Materials m ON cs.MaterialId=m.Id
              ORDER BY cs.Id").AsList();
    }

