using System;
using System.Collections.Generic;
using System.Linq;
using System.Windows.Forms;
using PanelEstimator.Data;
using PanelEstimator.Models;

namespace PanelEstimator.Forms
{
    public partial class MainForm : Form
    {
        private readonly PriceRepository _repo = new();
        private List<Material> _materials = [];

        public MainForm()
        {
            InitializeComponent();
            SetupGridColumns();
            LoadAllData();
        }

        // ================================================================
        // 그리드 컬럼 설정
        // ================================================================
        private void SetupGridColumns()
        {
            // 판넬 단가
            dgvPanelPrices.Columns.AddRange(
                new DataGridViewTextBoxColumn { Name = "Id", HeaderText = "ID", Width = 50, ReadOnly = true },
                new DataGridViewTextBoxColumn { Name = "MaterialName", HeaderText = "재질", Width = 80, ReadOnly = true },
                new DataGridViewTextBoxColumn { Name = "ProductTypeName", HeaderText = "제품유형", Width = 120, ReadOnly = true },
                new DataGridViewTextBoxColumn { Name = "GradeName", HeaderText = "등급", Width = 100, ReadOnly = true },
                new DataGridViewTextBoxColumn { Name = "ThicknessMm", HeaderText = "두께(mm)", Width = 80 },
                new DataGridViewTextBoxColumn { Name = "UnitPrice", HeaderText = "단가(원/평)", Width = 100 },
                new DataGridViewTextBoxColumn { Name = "FireRatingMin", HeaderText = "내화(분)", Width = 70 },
                new DataGridViewTextBoxColumn { Name = "Notes", HeaderText = "비고", Width = 150 }
            );
            dgvPanelPrices.AutoSizeColumnsMode = DataGridViewAutoSizeColumnsMode.Fill;

            // 재질
            dgvMaterials.Columns.AddRange(
                new DataGridViewTextBoxColumn { Name = "Id", HeaderText = "ID", Width = 40, ReadOnly = true },
                new DataGridViewTextBoxColumn { Name = "Name", HeaderText = "재질명", FillWeight = 40 },
                new DataGridViewTextBoxColumn { Name = "Description", HeaderText = "설명", FillWeight = 40 },
                new DataGridViewTextBoxColumn { Name = "SortOrder", HeaderText = "순서", Width = 50 }
            );
            dgvMaterials.CellEndEdit += DgvMaterials_CellEndEdit;

            // 제품유형
            dgvProductTypes.Columns.AddRange(
                new DataGridViewTextBoxColumn { Name = "Id", HeaderText = "ID", Width = 40, ReadOnly = true },
                new DataGridViewTextBoxColumn { Name = "MaterialName", HeaderText = "재질", Width = 70, ReadOnly = true },
                new DataGridViewComboBoxColumn { Name = "MaterialId", HeaderText = "재질선택", Width = 80 },
                new DataGridViewTextBoxColumn { Name = "Name", HeaderText = "유형명", FillWeight = 40 },
                new DataGridViewTextBoxColumn { Name = "SortOrder", HeaderText = "순서", Width = 50 }
            );
            dgvProductTypes.CellEndEdit += DgvProductTypes_CellEndEdit;

            // 등급
            dgvGrades.Columns.AddRange(
                new DataGridViewTextBoxColumn { Name = "Id", HeaderText = "ID", Width = 40, ReadOnly = true },
                new DataGridViewTextBoxColumn { Name = "MaterialName", HeaderText = "재질", Width = 70, ReadOnly = true },
                new DataGridViewComboBoxColumn { Name = "MaterialId", HeaderText = "재질선택", Width = 80 },
                new DataGridViewTextBoxColumn { Name = "Name", HeaderText = "등급명", FillWeight = 40 },
                new DataGridViewTextBoxColumn { Name = "SortOrder", HeaderText = "순서", Width = 50 }
            );
            dgvGrades.CellEndEdit += DgvGrades_CellEndEdit;

            // 색상 할증
            dgvColorSurcharges.Columns.AddRange(
                new DataGridViewTextBoxColumn { Name = "Id", HeaderText = "ID", Width = 40, ReadOnly = true },
                new DataGridViewTextBoxColumn { Name = "MaterialName", HeaderText = "재질", Width = 80, ReadOnly = true },
                new DataGridViewComboBoxColumn { Name = "MaterialId", HeaderText = "재질선택", Width = 90 },
                new DataGridViewTextBoxColumn { Name = "ColorName", HeaderText = "색상명", FillWeight = 30 },
                new DataGridViewTextBoxColumn { Name = "SurchargePerSide", HeaderText = "일면당 할증(원)", Width = 100 },
                new DataGridViewTextBoxColumn { Name = "Notes", HeaderText = "비고", FillWeight = 20 }
            );
            dgvColorSurcharges.CellEndEdit += DgvColorSurcharges_CellEndEdit;

            // 옵션 할증
            dgvOptionSurcharges.Columns.AddRange(
                new DataGridViewTextBoxColumn { Name = "Id", HeaderText = "ID", Width = 40, ReadOnly = true },
                new DataGridViewTextBoxColumn { Name = "MaterialName", HeaderText = "재질", Width = 80, ReadOnly = true },
                new DataGridViewComboBoxColumn { Name = "MaterialId", HeaderText = "재질선택", Width = 90 },
                new DataGridViewTextBoxColumn { Name = "OptionName", HeaderText = "옵션명", FillWeight = 30 },
                new DataGridViewTextBoxColumn { Name = "SurchargeAmount", HeaderText = "할증(원)", Width = 90 },
                new DataGridViewTextBoxColumn { Name = "Notes", HeaderText = "비고", FillWeight = 20 }
            );
            dgvOptionSurcharges.CellEndEdit += DgvOptionSurcharges_CellEndEdit;

            // 컬러강판
            dgvColorSteel.Columns.AddRange(
                new DataGridViewTextBoxColumn { Name = "Id", HeaderText = "ID", Width = 40, ReadOnly = true },
                new DataGridViewTextBoxColumn { Name = "Name", HeaderText = "품명", FillWeight = 40 },
                new DataGridViewTextBoxColumn { Name = "ThicknessMm", HeaderText = "두께(T)", Width = 70 },
                new DataGridViewTextBoxColumn { Name = "UnitPrice", HeaderText = "단가(원)", Width = 80 },
                new DataGridViewTextBoxColumn { Name = "Notes", HeaderText = "비고", FillWeight = 30 }
            );
            dgvColorSteel.CellEndEdit += DgvColorSteel_CellEndEdit;

            // PC 채광판
            dgvSkylight.Columns.AddRange(
                new DataGridViewTextBoxColumn { Name = "Id", HeaderText = "ID", Width = 40, ReadOnly = true },
                new DataGridViewTextBoxColumn { Name = "Name", HeaderText = "품명", FillWeight = 40 },
                new DataGridViewTextBoxColumn { Name = "ThicknessMm", HeaderText = "두께(T)", Width = 70 },
                new DataGridViewTextBoxColumn { Name = "UnitPrice", HeaderText = "단가(원)", Width = 80 },
                new DataGridViewTextBoxColumn { Name = "Notes", HeaderText = "비고", FillWeight = 30 }
            );
            dgvSkylight.CellEndEdit += DgvSkylight_CellEndEdit;

            // 부자재
            dgvAccessories.Columns.AddRange(
                new DataGridViewTextBoxColumn { Name = "Id", HeaderText = "ID", Width = 40, ReadOnly = true },
                new DataGridViewTextBoxColumn { Name = "Category", HeaderText = "분류", Width = 70 },
                new DataGridViewTextBoxColumn { Name = "Name", HeaderText = "품명", FillWeight = 30 },
                new DataGridViewTextBoxColumn { Name = "Specification", HeaderText = "규격", FillWeight = 25 },
                new DataGridViewTextBoxColumn { Name = "Unit", HeaderText = "단위", Width = 45 },
                new DataGridViewTextBoxColumn { Name = "UnitPrice", HeaderText = "단가", Width = 70 },
                new DataGridViewTextBoxColumn { Name = "Notes", HeaderText = "비고", FillWeight = 20 }
            );
            dgvAccessories.CellEndEdit += DgvAccessories_CellEndEdit;

            // 샷시/방화문
            dgvSash.Columns.AddRange(
                new DataGridViewTextBoxColumn { Name = "Id", HeaderText = "ID", Width = 40, ReadOnly = true },
                new DataGridViewTextBoxColumn { Name = "Type", HeaderText = "유형", FillWeight = 30 },
                new DataGridViewTextBoxColumn { Name = "Width", HeaderText = "폭(mm)", Width = 70 },
                new DataGridViewTextBoxColumn { Name = "Height", HeaderText = "높이(mm)", Width = 70 },
                new DataGridViewTextBoxColumn { Name = "PanelThicknessMm", HeaderText = "판넬두께", Width = 70 },
                new DataGridViewTextBoxColumn { Name = "UnitPrice", HeaderText = "단가(원)", Width = 80 },
                new DataGridViewTextBoxColumn { Name = "Notes", HeaderText = "비고", FillWeight = 20 }
            );
            dgvSash.CellEndEdit += DgvSash_CellEndEdit;
        }

        // ================================================================
        // 데이터 로드
        // ================================================================
        private void LoadAllData()
        {
            LoadMaterials();
            LoadProductTypes();
            LoadGrades();
            LoadPanelPrices();
            LoadColorSurcharges();
            LoadOptionSurcharges();
            LoadColorSteel();
            LoadSkylight();
            LoadAccessories();
            LoadSash();
        }

        private void LoadMaterials()
        {
            _materials = _repo.GetMaterials();

            // 필터 콤보박스
            cboMaterial.DataSource = null;
            var filterList = new List<Material> { new() { Id = 0, Name = "(전체)" } };
            filterList.AddRange(_materials);
            cboMaterial.DataSource = filterList;
            cboMaterial.DisplayMember = "Name";
            cboMaterial.ValueMember = "Id";

            // 재질 그리드
            dgvMaterials.Rows.Clear();
            foreach (var m in _materials)
            {
                var idx = dgvMaterials.Rows.Add();
                var row = dgvMaterials.Rows[idx];
                row.Cells["Id"].Value = m.Id;
                row.Cells["Name"].Value = m.Name;
                row.Cells["Description"].Value = m.Description;
                row.Cells["SortOrder"].Value = m.SortOrder;
                row.Tag = m;
            }

            // 콤보 컬럼 데이터소스 갱신
            UpdateMaterialComboColumns();
        }

        private void UpdateMaterialComboColumns()
        {
            var items = _materials.Select(m => new { m.Id, m.Name }).ToList();

            void SetCombo(DataGridView dgv, string colName)
            {
                if (dgv.Columns[colName] is DataGridViewComboBoxColumn col)
                {
                    col.DataSource = items.ToList();
                    col.DisplayMember = "Name";
                    col.ValueMember = "Id";
                }
            }

            SetCombo(dgvProductTypes, "MaterialId");
            SetCombo(dgvGrades, "MaterialId");
            SetCombo(dgvColorSurcharges, "MaterialId");
            SetCombo(dgvOptionSurcharges, "MaterialId");
        }

        private void LoadProductTypes()
        {
            var list = _repo.GetProductTypes();

            // 필터 콤보
            cboProductType.DataSource = null;
            var filterList = new List<ProductType> { new() { Id = 0, Name = "(전체)" } };
            filterList.AddRange(list);
            cboProductType.DataSource = filterList;
            cboProductType.DisplayMember = "Name";
            cboProductType.ValueMember = "Id";

            // 그리드
            dgvProductTypes.Rows.Clear();
            foreach (var pt in list)
            {
                var idx = dgvProductTypes.Rows.Add();
                var row = dgvProductTypes.Rows[idx];
                row.Cells["Id"].Value = pt.Id;
                row.Cells["MaterialName"].Value = pt.MaterialName;
                row.Cells["MaterialId"].Value = pt.MaterialId;
                row.Cells["Name"].Value = pt.Name;
                row.Cells["SortOrder"].Value = pt.SortOrder;
                row.Tag = pt;
            }
        }

        private void LoadGrades()
        {
            var list = _repo.GetGrades();
            dgvGrades.Rows.Clear();
            foreach (var g in list)
            {
                var idx = dgvGrades.Rows.Add();
                var row = dgvGrades.Rows[idx];
                row.Cells["Id"].Value = g.Id;
                row.Cells["MaterialName"].Value = g.MaterialName;
                row.Cells["MaterialId"].Value = g.MaterialId;
                row.Cells["Name"].Value = g.Name;
                row.Cells["SortOrder"].Value = g.SortOrder;
                row.Tag = g;
            }
        }

        private void LoadPanelPrices()
        {
            int? ptId = null;
            if (cboProductType.SelectedValue is int v && v > 0) ptId = v;

            // 재질 필터 → 제품유형 필터로 변환
            if (ptId == null && cboMaterial.SelectedValue is int matId && matId > 0)
            {
                // 해당 재질의 제품유형 ID 목록으로 필터
                var pts = _repo.GetProductTypes(matId);
                var list = new List<PanelPrice>();
                foreach (var pt in pts)
                    list.AddRange(_repo.GetPanelPrices(pt.Id));
                FillPanelPriceGrid(list);
                return;
            }

            FillPanelPriceGrid(_repo.GetPanelPrices(ptId));
        }

        private void FillPanelPriceGrid(List<PanelPrice> list)
        {
            dgvPanelPrices.Rows.Clear();
            foreach (var pp in list)
            {
                var idx = dgvPanelPrices.Rows.Add();
                var row = dgvPanelPrices.Rows[idx];
                row.Cells["Id"].Value = pp.Id;
                row.Cells["MaterialName"].Value = pp.MaterialName;
                row.Cells["ProductTypeName"].Value = pp.ProductTypeName;
                row.Cells["GradeName"].Value = pp.GradeName;
                row.Cells["ThicknessMm"].Value = pp.ThicknessMm;
                row.Cells["UnitPrice"].Value = pp.UnitPrice;
                row.Cells["FireRatingMin"].Value = pp.FireRatingMin;
                row.Cells["Notes"].Value = pp.Notes;
                row.Tag = pp;
            }
        }

        private void LoadColorSurcharges()
        {
            var list = _repo.GetColorSurcharges();
