        }

        // ================================================================
        // 헬퍼
        // ================================================================
        private static string CellStr(DataGridViewRow row, string col) =>
            row.Cells[col].Value?.ToString()?.Trim() ?? "";

        private static int CellInt(DataGridViewRow row, string col) =>
            int.TryParse(row.Cells[col].Value?.ToString(), out var v) ? v : 0;

        private static int? CellIntNull(DataGridViewRow row, string col)
        {
            var s = row.Cells[col].Value?.ToString();
            return int.TryParse(s, out var v) ? v : null;
        }

        private static double CellDouble(DataGridViewRow row, string col) =>
            double.TryParse(row.Cells[col].Value?.ToString(), out var v) ? v : 0;

        private void DeleteSelected(DataGridView dgv, Action<int> deleteAction, Action reloadAction)
        {
            if (dgv.CurrentRow == null) return;
            var id = CellInt(dgv.CurrentRow, "Id");
            if (id == 0) return;

            if (MessageBox.Show("선택한 항목을 삭제하시겠습니까?", "확인",
                    MessageBoxButtons.YesNo, MessageBoxIcon.Question) != DialogResult.Yes) return;

            try
            {
                deleteAction(id);
                reloadAction();
            }
            catch (Exception ex)
            {
                MessageBox.Show($"삭제 실패: {ex.Message}", "오류", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }

        // ================================================================
        // 탭1: 판넬 단가
        // ================================================================
        private void btnRefreshPrice_Click(object sender, EventArgs e) => LoadPanelPrices();

        private void btnAddPrice_Click(object sender, EventArgs e)
        {
            // 제품유형과 등급이 있어야 추가 가능
            var productTypes = _repo.GetProductTypes();
            var grades = _repo.GetGrades();
            if (productTypes.Count == 0 || grades.Count == 0)
            {
                MessageBox.Show("먼저 재질/유형/등급 탭에서 데이터를 추가하세요.", "안내");
                return;
            }

            var pp = new PanelPrice
            {
                ProductTypeId = productTypes[0].Id,
                GradeId = grades[0].Id,
                ThicknessMm = 50,
                UnitPrice = 0
            };
            _repo.SavePanelPrice(pp);
            LoadPanelPrices();
        }

        private void btnDeletePrice_Click(object sender, EventArgs e) =>
            DeleteSelected(dgvPanelPrices, _repo.DeletePanelPrice, LoadPanelPrices);

        private void dgvPanelPrices_CellEndEdit(object sender, DataGridViewCellEventArgs e)
        {
            if (e.RowIndex < 0) return;
            var row = dgvPanelPrices.Rows[e.RowIndex];
            if (row.Tag is not PanelPrice pp) return;

            pp.ThicknessMm = CellInt(row, "ThicknessMm");
            pp.UnitPrice = CellInt(row, "UnitPrice");
            pp.FireRatingMin = CellIntNull(row, "FireRatingMin");
            pp.Notes = CellStr(row, "Notes");

            try { _repo.SavePanelPrice(pp); }
            catch (Exception ex)
            {
                MessageBox.Show($"저장 실패: {ex.Message}", "오류");
                LoadPanelPrices();
            }
        }

        // ================================================================
        // 탭2: 재질
        // ================================================================
        private void btnAddMaterial_Click(object sender, EventArgs e)
        {
            var m = new Material { Name = "신규재질", SortOrder = _materials.Count };
            _repo.SaveMaterial(m);
            LoadMaterials();
            LoadProductTypes();
            LoadGrades();
        }

        private void btnDeleteMaterial_Click(object sender, EventArgs e) =>
