using PanelEstimator.Data;
using PanelEstimator.Forms;

namespace PanelEstimator;

static class Program
{
    [STAThread]
    static void Main()
    {
        ApplicationConfiguration.Initialize();

        // 전역 예외 핸들러
        Application.ThreadException += (_, e) => LogCrash(e.Exception);
        AppDomain.CurrentDomain.UnhandledException += (_, e) =>
        {
            if (e.ExceptionObject is Exception ex) LogCrash(ex);
        };

        // DB 초기화 (exe 옆에 PanelEstimator.db)
        var dbPath = Path.Combine(AppContext.BaseDirectory, "PanelEstimator.db");
        Database.Initialize(dbPath);

        Application.Run(new MainForm());
    }

    private static void LogCrash(Exception ex)
    {
        try
        {
            var logPath = Path.Combine(AppContext.BaseDirectory, "crash.log");
            var msg = $"[{DateTime.Now:yyyy-MM-dd HH:mm:ss}] {ex.Source}: {ex.Message}\n{ex.StackTrace}\n\n";
            File.AppendAllText(logPath, msg);
        }
        catch { /* 로그 기록 실패 무시 */ }
    }
}

