        for c in row:
            if c.value is not None:
                vals.append(f'{c.coordinate}={c.value}')
        if vals:
            print(' | '.join(vals))
"

python -c "
import openpyxl
wb = openpyxl.load_workbook(r'C:/Users/Administrator/Desktop/Panel/24 유창건설 2월.xlsx', data_only=True)
print('시트 목록:', wb.sheetnames)
for sn in wb.sheetnames:
    ws = wb[sn]
    print(f'\n=== 시트: {sn} (행:{ws.max_row}, 열:{ws.max_column}) ===')
    for row in ws.iter_rows(min_row=1, max_row=min(ws.max_row, 60), values_only=False):
        vals = []
        for c in row:
            if c.value is not None:
                vals.append(f'{c.coordinate}={c.value}')
        if vals:
            print(' | '.join(vals))
"
